figure.sourcecode:
Signature_With_Receipt = #6.18(COSE_Sign1)
cose-label = int / text cose-values = any
Protected_Header = { * cose-label => cose-values }
Unprotected_Header = { &(receipts: 394) => [+ bstr .cbor Receipt] * cose-label => cose-values }
COSE_Sign1 = [ protected : bstr .cbor Protected_Header unprotected : Unprotected_Header payload : bstr / nil signature : bstr ]
Receipt = Receipt_For_Inclusion / Receipt_For_Consistency
; Note the proof formats shown here are for RFC9162_SHA256. ; Other VDSs may have different proof formats.
Receipt_For_Inclusion = #6.18(Signed_Inclusion_Proof)
Signed_Inclusion_Proof = [ protected : bstr .cbor RFC9162_SHA256_Inclusion_Protected_Header, unprotected : RFC9162_SHA256_Inclusion_Unprotected_Header, payload : bstr / nil, signature : bstr ]
RFC9162_SHA256_Inclusion_Protected_Header = { &(alg: 1) => int &(vds: 395) => int * cose-label => cose-values }
RFC9162_SHA256_Inclusion_Unprotected_Header = { &(vdp: 396) => RFC9162_SHA256_Verifiable_Inclusion_Proofs * cose-label => cose-values }
RFC9162_SHA256_Verifiable_Inclusion_Proofs = { &(inclusion-proof: -1) => RFC9162_SHA256_Inclusion_Proofs }
RFC9162_SHA256_Inclusion_Proofs = [ + RFC9162_SHA256_Inclusion_Proof ]
RFC9162_SHA256_Inclusion_Proof = bstr .cbor RFC9162_SHA256_Inclusion_Proof_Content
RFC9162_SHA256_Inclusion_Proof_Content = [ tree_size: uint, leaf_index: uint, inclusion_path:[ + bstr ] ]
Receipt_For_Consistency = #6.18(Signed_Consistency_Proof)
Signed_Consistency_Proof = [ protected : bstr .cbor RFC9162_SHA256_Consistency_Protected_Header, unprotected : RFC9162_SHA256_Consistency_Unprotected_Header, payload : bstr / nil, ; Newer Merkle Tree root signature : bstr ]
RFC9162_SHA256_Consistency_Protected_Header = { &(alg: 1) => int, &(vds: 395) => int, * cose-label => cose-values }
RFC9162_SHA256_Consistency_Unprotected_Header = { &(vdp: 396) => RFC9162_SHA256_Verifiable_Consistency_Proofs * cose-label => cose-values }
RFC9162_SHA256_Verifiable_Consistency_Proofs = { &(consistency-proof: -2) => RFC9162_SHA256_Consistency_Proofs }
RFC9162_SHA256_Consistency_Proofs = [ + RFC9162_SHA256_Consistency_Proof ]
RFC9162_SHA256_Consistency_Proof = bstr .cbor RFC9162_SHA256_Consistency_Proof_Content
RFC9162_SHA256_Consistency_Proof_Content = [ tree_size_1: uint, tree_size_2: uint, consistency_path: [ + bstr ] ]

/ cose-sign1 / 18([
  / protected   / <<{
    / kid / 4 : h'bc297b51...e4edf0de',
    / algorithm / 1 : -7,  # ES256
  }>>,
  / unprotected / {
    / receipts / 394 : [
      <</ cose-sign1 / 18([
          / protected   / <<{
            / kid / 4 : h'abcdef12...34567890',
            / algorithm / 1 : -7,  # ES256
            / vds       / 395 : 1, # RFC9162_SHA256
          }>>,
          / unprotected / {
            / proofs / 396 : {
              / inclusion / -1 : [
                <<[
                  / size / 9, / leaf / 8,
                  / inclusion path /
                  [ h'7558a95f...e02e35d6' ]
                ]>>
              ],
            },
          },
          / payload     / null,
          / signature   / h'02d227ed...ccd3774f'
        ])>>,
        <</ cose-sign1 / 18([
          / protected   / <<{
            / kid / 4 : h'abcdef12...34567890',
            / algorithm / 1 : -7,  # ES256
            / vds       / 395 : 1, # RFC9162_SHA256
          }>>,
          / unprotected / {
            / proofs / 396 : {
              / inclusion / -1 : [
                <<[
                  / size / 6, / leaf / 5,
                  / inclusion path /
                  [ h'9352f974...4ffa7ce0',
                    h'54806f32...f007ea06' ]
                ]>>
              ],
            },
          },
          / payload     / null,
          / signature   / h'36581f38...a5581960'
        ])>>
    ],
  },
  / payload     / h'0167c57c...deeed6d4',
  / signature   / h'2544f2ed...5840893b'
])

inclusion-proofs = [ + inclusion-proof ]

verifiable-proofs = {
  &(inclusion-proof: -1) => inclusion-proofs
}

unprotected-header-map = {
  &(vdp: 396) => verifiable-proofs
  * cose-label => cose-value
}

/ cose-sign1 / 18([
  / protected   / <<{
    / algorithm / 1 : -7,  # ES256
    / vds       / 395 : 1, # RFC9162_SHA256
  }>>,
  / unprotected / {
    / proofs / 396 : {
      / inclusion / -1 : [
        <<[
          / size / 20, / leaf / 17,
          / inclusion path /
          [ h'fc9f050f...221c92cb',
            h'bd0136ad...6b28cf21',
            h'd68af9d6...93b1632b' ]
        ]>>
      ],
    },
  },
  / payload     / null,
  / signature   / h'de24f0cc...9a5ade89'
])

